import React from 'react';
import { BarChart3, Target, Zap, ShieldCheck } from 'lucide-react';

const StatisticsTab = () => {
  // Mock data representing your evaluate.py output
  const metrics = [
    { label: "Model Accuracy", value: "94.2%", icon: <Target className="text-green-500" /> },
    { label: "Avg. Latency", value: "142ms", icon: <Zap className="text-yellow-500" /> },
    { label: "Calibration (ECE)", value: "0.042", icon: <ShieldCheck className="text-blue-500" /> },
    { label: "Files Analyzed", value: "1,204", icon: <BarChart3 className="text-purple-500" /> }
  ];

  return (
    <div className="animate-in fade-in slide-in-from-bottom duration-500 space-y-8">
      {/* KPI Grid */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {metrics.map((m, i) => (
          <div key={i} className="bg-[#1e293b] p-6 rounded-2xl border border-slate-800 shadow-xl">
            <div className="flex items-center gap-3 mb-2">
              {m.icon}
              <span className="text-[10px] uppercase font-black text-slate-500 tracking-widest">{m.label}</span>
            </div>
            <p className="text-2xl font-mono font-bold text-white">{m.value}</p>
          </div>
        ))}
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-[#1e293b] p-6 rounded-2xl border border-slate-800">
          <h3 className="text-white font-bold mb-4 flex items-center gap-2">
            <BarChart3 size={18} /> Confusion Matrix (Behavioral Mapping)
          </h3>
          <div className="aspect-square bg-slate-900 rounded-xl overflow-hidden flex items-center justify-center border border-slate-800">
             {/* Replace src with actual path to your generated confusion_matrix.png */}
             <img src="/confusion_matrix.png" alt="Confusion Matrix" className="w-full h-full object-contain opacity-80" />
          </div>
        </div>

        <div className="bg-[#1e293b] p-6 rounded-2xl border border-slate-800">
          <h3 className="text-white font-bold mb-4 flex items-center gap-2">
            <ShieldCheck size={18} /> Reliability Diagram (Calibration)
          </h3>
          <div className="aspect-square bg-slate-900 rounded-xl overflow-hidden flex items-center justify-center border border-slate-800">
             {/* Replace src with actual path to your generated calibration_plot.png */}
             <img src="/calibration_plot.png" alt="Reliability Diagram" className="w-full h-full object-contain opacity-80" />
          </div>
        </div>
      </div>
    </div>
  );
};

export default StatisticsTab;
